source:
Opcode -> {
  -> Text:
  -> Binary:
  -> Ping:
  -> Pong:
  -> Close:
}

Frame -> {
  Opcode:opcode
  bool:fin -> true
  String:payload
}

Send -> { Frame:frame }
Receive -> { Frame:frame }

handler -> {
  Receive -< e {
    -> e.frame.opcode ? {
      Ping: -> >- Send{frame -> Frame{opcode -> Pong:}}
      Close: -> none
      -> e.frame.payload
    }
  }
}
